<template>
  <div class="todo">
    <el-container >
      <el-header > 
        <template>
          <el-alert title="addTodo is successful!" type="success" show-icon center v-show="isAdded"></el-alert>
        </template>
        <template>
          <el-alert
            title="deleteTodo is successful!"
            type="warning"
            show-icon
            center
            v-show="isDeleted"
          ></el-alert>
        </template>
        <el-row type="flex" justify="center">
          <el-breadcrumb type="flex" justify="center" separator-class="el-icon-arrow-right">
            <el-input
              maxlength="15"
              show-word-limit
              clearable
              v-model="input"
              placeholder="input todo for your search"
              style="width:auto;"
            ></el-input>
            <el-button type="success" :xs="24" @click="isModel = true">Add ToDo</el-button>
            <el-dialog title="提示" :visible.sync="isModel" width="80%" center>
              <template>
                <el-alert
                  title="your input todo title or content is null"
                  type="warning"
                  show-icon
                  center
                  v-show="isError"
                ></el-alert>
              </template>
              <div>
                <el-input placeholder="input your todo title" v-model="todo.title">
                  <template slot="prepend">title</template>
                </el-input>
              </div>
              <el-input
                type="textarea"
                :autosize="{ minRows: 2, maxRows: 4}"
                placeholder="input your todo content"
                v-model="todo.content"
              ></el-input>
              <div class="radio">
                <el-radio v-model="todo.completed" :label="true">completed</el-radio>
                <el-radio v-model="todo.completed" :label="false">doing</el-radio>
              </div>
              <p>written time : {{ todo.updateTime = new Date().toLocaleString() }}</p>
              <span slot="footer" class="dialog-footer">
                <el-button @click="isModel = false">取 消</el-button>
                <el-button type="primary" @click="addTodo">确 定</el-button>
              </span>
            </el-dialog>
          </el-breadcrumb>
        </el-row>
</el-header>
<el-main >
        <el-row :gutter="20" type="flex"  style="flex-wrap:wrap;">
          <el-col
            :lg="8"
            :sm="12"
            :xs="24"
            v-for="(todo,index) in  filterTodos"
            :key="todo.id"
            style="margin-top:10px;"
          >
            <el-card class="box-card" shadow="hover" :class="{isCompleted:todo.completed}">
              <div slot="header" class="clearfix">
                <router-link :to="'/todo/' + todo.id">
                  <el-button style="float: left; padding:5 px" icon="el-icon-edit" circle></el-button>
                </router-link>
                <el-input
                  clearable
                  v-model="todo.title"
                  placeholder="input todo of title"
                  readonly
                  style="width:60%;"
                ></el-input>
                <el-button
                  style="float: right; padding:5 px"
                  icon="el-icon-delete"
                  circle
                  @click="deleteTodo([todo.id,index])"
                ></el-button>
              </div>
              <el-input
                type="textarea"
                :autosize="{ minRows: 6, maxRows: 8}"
                placeholder="input your todo"
                v-model="todo.content"
                readonly
              ></el-input>
              <p>written time : {{ todo.updateTime }}</p>
            </el-card>
          </el-col>
        </el-row>
      </el-main>
    </el-container>
    <router-view></router-view>
  </div>
</template>
<script>
export default {
  data() {
    return {
      todos: [],
      input: "",
      isAdded: false,
      isDeleted: false,
      data: "",
      isModel: false,
      todo: {
        title: "",
        content: "",
        completed: false,
        updateTime:new Date().toLocaleString()
      },
      isError: false
    };
  },
  computed: {
    // 根据 todo.title 查找todo
    filterTodos() {
      return this.todos.filter(
        todo => todo.title.match(this.input) || todo.content.match(this.input)
      );
    }
  },
  methods: {
    // 添加todo
    addTodo() {
      if (this.todo.title && this.todo.content) {
        this.$http.post("/api/todos.json", this.todo).then(response => {
          this.$http.get("/api/todos.json").then(res => {
            // console.log(res.data);
            for (var d in res.data) {
              if (d === response.data.name) {
                res.data[d].id = d;
                this.todos.unshift(res.data[d]);
              }
            }
          });
          this.todo.title = "";
          this.todo.content = "";
          this.isModel = false;
          this.isAdded = true;
          setTimeout(() => (this.isAdded = false), 3000);
        });
      } else {
        this.isError = true;
         setTimeout(() => (this.isError = false), 3000);
      }
    },
    // 删除 todo
    deleteTodo(arr) {
      this.$http.delete("/api/todos/" + arr[0] + ".json").then(() => {
        // console.log(this.todos);
        this.todos.splice(arr[1], 1);
        this.isDeleted = true;
        setTimeout(() => (this.isDeleted = false), 3000);
      });
    }
  },
  // 获取数据
  created() {
    this.$http.get("/api/todos.json").then(res => {
      this.data = res.data;
      for (var d in res.data) {
        //遍历对象 给每个todo 添加id
        res.data[d].id = d;
        this.todos.unshift(res.data[d]);
      }
      // console.log(this.filterTodos);
    });
  }
};
</script>
<style scoped>
.box-card {
  background: #909399;
  color: #fff;
  border-radius: 10px;
}
.isCompleted {
  background: #67c23a;
  color: #fff;
  border-radius: 10px;
}
.radio {
  padding: 10px;
}
</style>


